package com.richemont.ce.ce_order.configuration;

import com.commercetools.api.models.subscription.MessageDeliveryPayload;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.richemont.ce.ce_order.service.OrderCancellationService;
import com.richemont.ce.ce_order.service.OrderCustomFieldUpdateEventService;
import com.richemont.ce.ce_order.service.PaymentStatusStateTransitionEventService;
import lombok.AllArgsConstructor;
import org.springframework.cloud.function.context.config.JsonMessageConverter;
import org.springframework.cloud.function.json.JacksonMapper;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.messaging.Message;

import java.util.function.Consumer;

@Configuration
@AllArgsConstructor
public class SolaceConfiguration {

    @Bean
    Consumer<Message<MessageDeliveryPayload>> paymentStatusStateTransitionUpdate(PaymentStatusStateTransitionEventService paymentStatusStateTransitionEventService) {
        return paymentStatusStateTransitionEventService::handlePaymentUpdatedEvent;
    }

    @Bean
    Consumer<MessageDeliveryPayload> orderCustomFieldUpdate(OrderCustomFieldUpdateEventService customFieldUpdateEventService) {
        return customFieldUpdateEventService;
    }

    @Bean
    Consumer<MessageDeliveryPayload> orderStateTransition(OrderCancellationService orderCancellationService) {
        return orderCancellationService::orderStateTransition;
    }

    @Bean
    public JsonMessageConverter customJsonMessageConverter(ObjectMapper objectMapper) {
        return new JsonMessageConverter(new JacksonMapper(objectMapper));
    }

}

