package com.richemont.ce.ce_order.commercetools.clients;

import com.commercetools.api.models.cart.Cart;
import com.commercetools.api.models.cart.CartPagedQueryResponse;
import com.commercetools.api.models.cart.CartUpdate;
import com.richemont.ce.CommercetoolsClientProvider;
import lombok.AllArgsConstructor;
import lombok.extern.log4j.Log4j2;
import org.springframework.stereotype.Service;

import java.util.List;
import java.util.UUID;

@Service
@AllArgsConstructor
@Log4j2
public class CTCartClient {

    public static final String EXPAND_LINE_ITEMS_CUSTOM_TYPE = "lineItems[*].custom.type";

    private final CommercetoolsClientProvider commercetoolsClientProvider;

    public Cart searchCartByPaymentId(String tenant, UUID paymentId, List<String> expands) {
        CartPagedQueryResponse cartPagedQueryResponse = commercetoolsClientProvider.getProjectApiRootByTenant(tenant)
                .carts()
                .get()
                .withWhere("paymentInfo(payments(id=:paymentId))", "paymentId", paymentId.toString())
                .addExpand(expands)
                .executeBlocking()
                .getBody();
        if (cartPagedQueryResponse.getCount() > 1) {
            throw new IllegalStateException(
                    "%s carts associated to payment id %s, only one is expected".formatted(cartPagedQueryResponse.getCount(), paymentId.toString()));
        }
        return cartPagedQueryResponse
                .getResults()
                .getFirst();
    }

    public Cart updateCart(final String tenant, final CartUpdate cartUpdate, final String cartId, final List<String> expands) {
        return commercetoolsClientProvider.getProjectApiRootWithConcurrencyRetryByTenant(tenant).carts()
                .withId(cartId)
                .post(cartUpdate)
                .withExpand(expands)
                .executeBlocking()
                .getBody();
    }

    public List<Cart> searchCartsByReturnNumber(final String tenant, final String returnNumber, final List<String> expands) {
        return commercetoolsClientProvider.getProjectApiRootByTenant(tenant)
            .carts()
            .get()
            .withWhere("custom(fields(returnNumber=:returnNumber))", "returnNumber", returnNumber)
            .withExpand(expands)
            .executeBlocking()
            .getBody()
            .getResults();
    }
